import { useState, useEffect } from "react";

function ViewApplications() {

  const [apps, setApps] = useState([]);

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  const updateStatus = (id, status) => {
    const updated = apps.map(app =>
      app.id === id ? { ...app, status } : app
    );

    setApps(updated);
    localStorage.setItem("applications", JSON.stringify(updated));

    alert(`Application ${status}`);
  };

  // Logged In User
  const logged = JSON.parse(localStorage.getItem("loggedInUser"));

  // Employees List
  const employees = JSON.parse(localStorage.getItem("employees")) || [];

  // Find current employee object
  const currentEmployee = employees.find(e => e.email === logged?.email);

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>

          {apps.length === 0 ? (
            <tr>
              <td colSpan="6">No Applications Yet</td>
            </tr>
          ) : (
            apps.map((a, index) => (
              <tr key={a.id}>
                <td>{index + 1}</td>

                {/* EMPLOYEE NAME */}
                <td>
                  {a.employeeName ||
                    currentEmployee?.name ||
                    "Unknown"}
                </td>

                {/* EMPLOYEE EMAIL */}
                <td>
                  {a.email ||
                    logged?.email ||
                    "N/A"}
                </td>

                <td>{a.jobTitle}</td>

                {/* STATUS */}
                <td>
                  <span
                    style={{
                      padding: "6px 12px",
                      borderRadius: "6px",
                      fontWeight: "600",
                      color: "white",
                      background:
                        a.status === "Approved"
                          ? "green"
                          : a.status === "Rejected"
                          ? "red"
                          : "#64748b"
                    }}
                  >
                    {a.status}
                  </span>
                </td>

                {/* ACTION BUTTONS */}
                <td style={{ display: "flex", gap: "14px" }}>
                  <button
                    style={{
                      background: "#16a34a",
                      color: "white",
                      padding: "8px 14px",
                      borderRadius: "6px",
                      border: "none",
                      cursor: "pointer"
                    }}
                    onClick={() => updateStatus(a.id, "Approved")}
                  >
                    Approve
                  </button>

                  <button
                    style={{
                      background: "#dc2626",
                      color: "white",
                      padding: "8px 14px",
                      borderRadius: "6px",
                      border: "none",
                      cursor: "pointer"
                    }}
                    onClick={() => updateStatus(a.id, "Rejected")}
                  >
                    Reject
                  </button>
                </td>
              </tr>
            ))
          )}

        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
